{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Physical World and Measurement",
      "description": "Competencies related to units, measurements, significant figures, uncertainty determination, dimensional analysis, and dimensions of physical quantities.",
      "competencies": [
        "Understand the need for measurement and systems of units including SI fundamental and derived units.",
        "Apply rules for significant figures and determine uncertainty in results.",
        "Perform dimensional analysis and apply it to physical problems."
      ],
      "unit_name": "Unit I: Physical World and Measurements",
      "chapter_name": "Units and Measurements"
    },
    {
      "code": "C2",
      "title": "Kinematics - Motion in a Straight Line",
      "description": "Competencies related to frame of reference, motion description using calculus concepts, velocity-time graphs, and uniformly accelerated motion.",
      "competencies": [
        "Define frame of reference and describe motion in a straight line."
      ],
      "unit_name": "Unit II: Kinematics",
      "chapter_name": "Motion in a Straight Line"
    },
    {
      "code": "C3",
      "title": "Kinematics - Motion in a Plane",
      "description": "Competencies related to vector operations, resolution of vectors, and motion in two dimensions including projectile and circular motion.",
      "competencies": [
        "Distinguish between scalar and vector quantities and perform vector addition/subtraction/multiplication."
      ],
      "unit_name": "Unit II: Kinematics",
      "chapter_name": "Motion in a Plane"
    },
    {
      "code": "C4",
      "title": "Laws of Motion",
      "description": "Competencies related to Newton's laws, momentum conservation, friction types, and dynamics of circular motion.",
      "competencies": [
        "Explain intuitive concepts of force, inertia, and Newton's three laws."
      ],
      "unit_name": "Unit III: Laws of Motion",
      "chapter_name": "Laws of Motion"
    },
    {
      "code": "C5",
      "title": "Work, Energy and Power",
      "description": "Competencies related to work done by forces, kinetic/potential energy, conservation laws, collisions, and power.",
      "competencies": [
        "Calculate work done by constant and variable forces."
      ],
      "unit_name": "Unit IV: Work, Energy and Power",
      "chapter_name": "Work, Energy and Power"
    },
    {
      "code": "C6",
      "title": "System of Particles and Rotational Motion",
      "description": "Competencies related to center of mass, torque, angular momentum conservation, rotational dynamics, moment of inertia, and equilibrium.",
      "competencies": [
        "Determine the center of mass for systems and rigid bodies."
      ],
      "unit_name": "Unit V: Motion of System of Particles and Rigid Body",
      "chapter_name": "System of Particles and Rotational Motion"
    },
    {
      "code": "C7",
      "title": "Gravitation",
      "description": "Competencies related to Kepler's laws, universal gravitation, variation of gravity, gravitational potential/energy, orbital mechanics, and escape speed.",
      "competencies": [
        "Apply Kepler's laws and the universal law of gravitation."
      ],
      "unit_name": "Unit VI: Gravitation",
      "chapter_name": "Gravitation"
    },
    {
      "code": "C8",
      "title": "Mechanical Properties of Solids",
      "description": "Competencies related to elasticity, stress-strain relationships, Hooke's law, moduli (Young's, Bulk, Shear), Poisson's ratio, and elastic energy.",
      "competencies": [
        "Analyze the relationship between stress and strain."
      ],
      "unit_name": "Unit VII: Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Solids"
    },
    {
      "code": "C9",
      "title": "Mechanical Properties of Fluids",
      "description": "Competencies related to fluid pressure, Pascal's law, viscosity, Stokes' law, Bernoulli's theorem, surface tension, and capillary action.",
      "competencies": [
        "Explain the principles behind hydraulic lifts/brakes using Pascal's law."
      ],
      "unit_name": "Unit VII: Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Fluids"
    },
    {
      "code": "C10",
      "title": "Thermal Properties of Matter",
      "description": "Competencies related to heat, temperature, expansion, specific heats, calorimetry, latent heat, and modes of heat transfer including radiation laws.",
      "competencies": [
        "Differentiate between conduction, convection, and radiation."
      ],
      "unit_name": "Unit VII: Properties of Bulk Matter",
      "chapter_name": "Thermal Properties of Matter"
    },
    {
      "code": "C11",
      "title": "Thermodynamics",
      "description": "Competencies related to thermal equilibrium, laws of thermodynamics (zeroth through second), state variables, and processes like isothermal/adiabatic.",
      "competencies": [
        "Apply the first law of thermodynamics."
      ],
      "unit_name": "Unit VIII: Thermodynamics",
      "chapter_name": "Thermodynamics"
    },
    {
      "code": "C12",
      "title": "Kinetic Theory of Gases",
      "description": "Competencies related to the equation of state, kinetic theory assumptions, pressure concept, temperature interpretation, degrees of freedom, and mean free path.",
      "competencies": [
        "Explain the kinetic theory basis for gas pressure."
      ],
      "unit_name": "Unit IX: Behaviour of Perfect Gases and Kinetic Theory of Gases",
      "chapter_name": "Kinetic Theory"
    },
    {
      "code": "C13",
      "title": "Oscillations",
      "description": "Competencies related to periodic motion, simple harmonic motion (SHM), energy in SHM, and the simple pendulum.",
      "competencies": [
        "Derive expressions for time period of a loaded spring."
      ],
      "unit_name": "Unit X: Oscillations and Waves",
      "chapter_name": "Oscillations"
    },
    {
      "code": "C14",
      "title": "Waves",
      "description": "Competencies related to wave types, speed, superposition principle, reflection, standing waves (strings/pipes), and beats.",
      "competencies": [
        "Explain the principle of superposition of waves."
      ],
      "unit_name": "Unit X: Oscillations and Waves",
      "chapter_name": "Waves"
    }
  ]
}
